example.code:
PUT _index_template/logs-template
{
  "index_patterns": ["logs-*"],
  "priority": 100,
  "template": {
    "settings": {
      "number_of_shards": 3,
      "number_of_replicas": 1,
      "index.lifecycle.name": "logs-policy",
      "index.lifecycle.rollover_alias": "logs",
      "index.refresh_interval": "5s",
      "index.translog.durability": "async"
    },
    "mappings": {
      "dynamic": "strict",
      "properties": {
        "@timestamp": { "type": "date" },
        "message": { "type": "text" },
        "level": { "type": "keyword" },
        "logger": { "type": "keyword" },
        "service": { "type": "keyword" },
        "version": { "type": "keyword" },
        "environment": { "type": "keyword" },
        "host": {
          "properties": {
            "name": { "type": "keyword" },
            "ip": { "type": "ip" }
          }
        },
        "trace_id": { "type": "keyword" },
        "span_id": { "type": "keyword" },
        "request_id": { "type": "keyword" },
        "user_id": { "type": "keyword" },
        "duration_ms": { "type": "long" },
        "error": {
          "properties": {
            "type": { "type": "keyword" },
            "message": { "type": "text" },
            "stack_trace": { "type": "text", "index": false }
          }
        },
        "http": {
          "properties": {
            "method": { "type": "keyword" },
            "path": { "type": "keyword" },
            "status_code": { "type": "short" }
          }
        }
      }
    }
  }
}

PUT _ilm/policy/logs-policy
{
  "policy": {
    "phases": {
      "hot": {
        "min_age": "0ms",
        "actions": {
          "rollover": {
            "max_primary_shard_size": "50gb",
            "max_age": "1d",
            "max_docs": 100000000
          },
          "set_priority": { "priority": 100 }
        }
      },
      "warm": {
        "min_age": "7d",
        "actions": {
          "shrink": { "number_of_shards": 1 },
          "forcemerge": { "max_num_segments": 1 },
          "set_priority": { "priority": 50 },
          "readonly": {}
        }
      },
      "cold": {
        "min_age": "30d",
        "actions": {
          "searchable_snapshot": {
            "snapshot_repository": "logs-snapshots"
          },
          "set_priority": { "priority": 0 }
        }
      },
      "delete": {
        "min_age": "90d",
        "actions": {
          "delete": {}
        }
      }
    }
  }
}

# /etc/logstash/conf.d/main.conf
input {
  beats {
    port => 5044
    ssl => true
    ssl_certificate => "/etc/logstash/certs/logstash.crt"
    ssl_key => "/etc/logstash/certs/logstash.key"
    ssl_certificate_authorities => ["/etc/logstash/certs/ca.crt"]
  }

  kafka {
    bootstrap_servers => "kafka:9092"
    topics => ["app-logs"]
    codec => json
    group_id => "logstash-consumer"
    auto_offset_reset => "latest"
  }
}

filter {
  # Parse JSON logs
  if [message] =~ /^\{/ {
    json {
      source => "message"
      skip_on_invalid_json => true
    }
  }

  # Parse common log formats
  if "_jsonparsefailure" in [tags] or ![level] {
    grok {
      match => {
        "message" => [
          "%{TIMESTAMP_ISO8601:timestamp} \[%{LOGLEVEL:level}\] %{DATA:logger} - %{GREEDYDATA:log_message}",
          "%{TIMESTAMP_ISO8601:timestamp} %{LOGLEVEL:level} %{GREEDYDATA:log_message}",
          "%{COMBINEDAPACHELOG}"
        ]
      }
      tag_on_failure => ["_grokparsefailure"]
    }
  }

  # Parse dates
  if [timestamp] {
    date {
      match => ["timestamp", "ISO8601", "yyyy-MM-dd HH:mm:ss,SSS", "yyyy-MM-dd HH:mm:ss"]
      target => "@timestamp"
      remove_field => ["timestamp"]
    }
  }

  # Add GeoIP for client IPs
  if [client_ip] {
    geoip {
      source => "client_ip"
      target => "geo"
      database => "/etc/logstash/GeoLite2-City.mmdb"
    }
  }

  # Normalize log levels
  if [level] {
    mutate {
      uppercase => ["level"]
    }
  }

  # Add environment and service tags
  mutate {
    add_field => {
      "[@metadata][index_prefix]" => "logs"
    }
  }

  # Extract service name from Kubernetes metadata
  if [kubernetes][labels][app] {
    mutate {
      add_field => { "service" => "%{[kubernetes][labels][app]}" }
    }
  }

  # Mask sensitive data
  mutate {
    gsub => [
      "message", "password[=:]\s*\S+", "password=[REDACTED]",
      "message", "api[_-]?key[=:]\s*\S+", "api_key=[REDACTED]",
      "message", "\b\d{16}\b", "[CARD_NUMBER_REDACTED]",
      "message", "\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b", "[EMAIL_REDACTED]"
    ]
  }

  # Remove unnecessary fields
  mutate {
    remove_field => ["agent", "ecs", "input", "log", "host.os"]
  }
}

output {
  elasticsearch {
    hosts => ["https://elasticsearch:9200"]
    index => "%{[@metadata][index_prefix]}-%{[service]}-%{+YYYY.MM.dd}"
    user => "logstash_writer"
    password => "${LOGSTASH_PASSWORD}"
    ssl => true
    ssl_certificate_verification => true
    cacert => "/etc/logstash/certs/ca.crt"
    action => "create"
  }

  # Dead letter queue for failed events
  if "_grokparsefailure" in [tags] or "_jsonparsefailure" in [tags] {
    file {
      path => "/var/log/logstash/failed-%{+YYYY-MM-dd}.json"
      codec => json_lines
    }
  }

  # Debug output (disable in production)
  # stdout { codec => rubydebug }
}

PUT _watcher/watch/high_error_rate
{
  "trigger": {
    "schedule": { "interval": "5m" }
  },
  "input": {
    "search": {
      "request": {
        "search_type": "query_then_fetch",
        "indices": ["logs-*"],
        "body": {
          "size": 0,
          "query": {
            "bool": {
              "filter": [
                { "range": { "@timestamp": { "gte": "now-5m" } } },
                { "term": { "level": "ERROR" } }
              ]
            }
          }
        }
      }
    }
  },
  "condition": {
    "compare": { "ctx.payload.hits.total.value": { "gt": 100 } }
  },
  "throttle_period": "15m",
  "actions": {
    "slack_notification": {
      "slack": {
        "account": "monitoring",
        "message": {
          "to": ["#alerts"],
          "text": "High error rate detected: {{ctx.payload.hits.total.value}} errors in last 5 minutes"
        }
      }
    },
    "email_notification": {
      "email": {
        "to": ["ops-team@example.com"],
        "subject": "ELK Alert: High Error Rate",
        "body": {
          "text": "Detected {{ctx.payload.hits.total.value}} errors in the last 5 minutes. Please investigate."
        }
      }
    }
  }
}

# main.tf
resource "aws_elasticsearch_domain" "logs" {
  domain_name           = var.domain_name
  elasticsearch_version = "OpenSearch_2.11"

  cluster_config {
    instance_type            = var.instance_type
    instance_count           = var.instance_count
    dedicated_master_enabled = var.dedicated_master_enabled
    dedicated_master_type    = var.dedicated_master_type
    dedicated_master_count   = var.dedicated_master_count
    zone_awareness_enabled   = var.zone_awareness_enabled

    zone_awareness_config {
      availability_zone_count = var.availability_zone_count
    }
  }

  ebs_options {
    ebs_enabled = true
    volume_type = "gp3"
    volume_size = var.volume_size
    iops        = var.volume_iops
    throughput  = var.volume_throughput
  }

  vpc_options {
    subnet_ids         = var.subnet_ids
    security_group_ids = [aws_security_group.elasticsearch.id]
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  advanced_security_options {
    enabled                        = true
    internal_user_database_enabled = true
    master_user_options {
      master_user_name     = var.master_user_name
      master_user_password = var.master_user_password
    }
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.elasticsearch.arn
    log_type                 = "INDEX_SLOW_LOGS"
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.elasticsearch.arn
    log_type                 = "SEARCH_SLOW_LOGS"
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.elasticsearch.arn
    log_type                 = "ES_APPLICATION_LOGS"
  }

  tags = var.tags
}

resource "aws_security_group" "elasticsearch" {
  name        = "${var.domain_name}-elasticsearch-sg"
  description = "Security group for Elasticsearch domain"
  vpc_id      = var.vpc_id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = var.allowed_security_groups
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = var.tags
}

resource "aws_cloudwatch_log_group" "elasticsearch" {
  name              = "/aws/elasticsearch/${var.domain_name}"
  retention_in_days = 30
  tags              = var.tags
}

resource "aws_cloudwatch_log_resource_policy" "elasticsearch" {
  policy_name = "${var.domain_name}-elasticsearch-log-policy"
  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "es.amazonaws.com"
        }
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream"
        ]
        Resource = "${aws_cloudwatch_log_group.elasticsearch.arn}:*"
      }
    ]
  })
}

# variables.tf
variable "domain_name" {
  description = "Name of the Elasticsearch domain"
  type        = string
}

variable "instance_type" {
  description = "Instance type for data nodes"
  type        = string
  default     = "r6g.large.elasticsearch"
}

variable "instance_count" {
  description = "Number of data nodes"
  type        = number
  default     = 3
}

variable "dedicated_master_enabled" {
  description = "Enable dedicated master nodes"
  type        = bool
  default     = true
}

variable "dedicated_master_type" {
  description = "Instance type for master nodes"
  type        = string
  default     = "r6g.large.elasticsearch"
}

variable "dedicated_master_count" {
  description = "Number of master nodes"
  type        = number
  default     = 3
}

variable "zone_awareness_enabled" {
  description = "Enable zone awareness"
  type        = bool
  default     = true
}

variable "availability_zone_count" {
  description = "Number of availability zones"
  type        = number
  default     = 3
}

variable "volume_size" {
  description = "EBS volume size in GB"
  type        = number
  default     = 500
}

variable "volume_iops" {
  description = "EBS volume IOPS"
  type        = number
  default     = 3000
}

variable "volume_throughput" {
  description = "EBS volume throughput in MiB/s"
  type        = number
  default     = 125
}

variable "vpc_id" {
  description = "VPC ID"
  type        = string
}

variable "subnet_ids" {
  description = "Subnet IDs for the domain"
  type        = list(string)
}

variable "allowed_security_groups" {
  description = "Security groups allowed to access Elasticsearch"
  type        = list(string)
}

variable "master_user_name" {
  description = "Master username"
  type        = string
  sensitive   = true
}

variable "master_user_password" {
  description = "Master password"
  type        = string
  sensitive   = true
}

variable "tags" {
  description = "Tags to apply to resources"
  type        = map(string)
  default     = {}
}

# outputs.tf
output "domain_endpoint" {
  description = "Elasticsearch domain endpoint"
  value       = aws_elasticsearch_domain.logs.endpoint
}

output "kibana_endpoint" {
  description = "Kibana endpoint"
  value       = aws_elasticsearch_domain.logs.kibana_endpoint
}

output "domain_arn" {
  description = "Elasticsearch domain ARN"
  value       = aws_elasticsearch_domain.logs.arn
}

#!/usr/bin/env bash
# es-pre-deploy.sh — refuse risky deploys when cluster isn't green
set -euo pipefail
ES=${ES_URL:?https://es.example:9200}
AUTH=${ES_AUTH:?user:pass}
HEALTH=$(curl -sSu "$AUTH" "$ES/_cluster/health" | jq -r '.status')
[[ "$HEALTH" == "green" ]] || { echo "ES status: $HEALTH (refuse)"; exit 2; }
PENDING=$(curl -sSu "$AUTH" "$ES/_cluster/pending_tasks" | jq '.tasks | length')
[[ "$PENDING" -lt 5 ]] || { echo "Pending tasks: $PENDING"; exit 3; }
JVM=$(curl -sSu "$AUTH" "$ES/_nodes/stats/jvm" | jq '[.nodes[].jvm.mem.heap_used_percent] | max')
[[ "$JVM" -lt 80 ]] || { echo "Heap pressure: ${JVM}%"; exit 4; }
echo "ES ready (status=$HEALTH heap=${JVM}%)"
